  case route_id do
    "Blue" -> %{type: :text, color: :blue, text: "BL"}
    "Orange" -> %{type: :text, color: :orange, text: "OL"}
    "Red" -> %{type: :text, color: :red, text: "RL"}
    _ -> %{type: :text, color: :green, text: "GL"}
  end
end

